      : rule.after === 1
        ? "1 day overdue"
        : `${rule.after} days overdue`;

  switch (rule.action) {
    case "advance_recurrence":
      return `${whenPrefix}: advance`;
    case "set_status":
      return rule.status ? `${whenPrefix}: set ${rule.status}` : `${whenPrefix}: set status`;
    case "clear_due_date":
      return `${whenPrefix}: clear due date`;
  }
}

