	if !hasDue {
		return types.ValidationError("overdue_action_rule requires a due date")
	}

	// advance_recurrence only makes sense for tasks that have a scheduled
	// recurrence rule to advance to. The set_status and clear_due_date actions
	// are valid for any task with a due date.
	if action.OverdueAction == dbgen.OverdueActionAdvanceRecurrence {
		if recurrenceType == dbgen.RecurrenceTypeOneOff || recurrenceType == dbgen.RecurrenceTypeOnDependency {
			return types.ValidationError(
				"advance_recurrence overdue action is not valid for one-off or dependency-driven tasks",
