package taskengine

import (
	"strings"
	"testing"

	"github.com/jackc/pgx/v5/pgtype"

	dbgen "github.com/sargunv/tend/server/internal/database/gen"
)

func nullOverdueAction(a dbgen.OverdueAction) dbgen.NullOverdueAction {
	return dbgen.NullOverdueAction{OverdueAction: a, Valid: true}
}

func statusName(name string) pgtype.Text {
	return pgtype.Text{String: name, Valid: true}
}

func TestValidateOverdueActionRule(t *testing.T) {
	tests := []struct {
		name           string
		afterDays      pgtype.Int4
		action         dbgen.NullOverdueAction
		statusName     pgtype.Text
		recurrenceType dbgen.RecurrenceType
		hasDue         bool
		wantErr        bool
		errContains    string
	}{
		// ─── No rule ─────────────────────────────────────────────────────────────
		{
			name:           "nil rule always valid",
			action:         dbgen.NullOverdueAction{Valid: false},
			recurrenceType: dbgen.RecurrenceTypeOneOff,
			hasDue:         false,
			wantErr:        false,
		},

		// ─── One-off tasks ─────────────────────────────────────────────────────────
		{
			name:           "one_off with clear_due_date",
			action:         nullOverdueAction(dbgen.OverdueActionClearDueDate),
			recurrenceType: dbgen.RecurrenceTypeOneOff,
			hasDue:         true,
			wantErr:        false,
		},
		{
			name:           "one_off with set_status",
			action:         nullOverdueAction(dbgen.OverdueActionSetStatus),
			statusName:     statusName("skipped"),
			recurrenceType: dbgen.RecurrenceTypeOneOff,
			hasDue:         true,
			wantErr:        false,
		},
		{
			name:           "one_off with advance_recurrence rejected",
			action:         nullOverdueAction(dbgen.OverdueActionAdvanceRecurrence),
			recurrenceType: dbgen.RecurrenceTypeOneOff,
			hasDue:         true,
			wantErr:        true,
			errContains:    "not valid for one-off or dependency-driven tasks",
		},

		// ─── On-dependency tasks ───────────────────────────────────────────────────
		{
			name:           "on_dependency with clear_due_date",
			action:         nullOverdueAction(dbgen.OverdueActionClearDueDate),
			recurrenceType: dbgen.RecurrenceTypeOnDependency,
			hasDue:         true,
			wantErr:        false,
		},
		{
			name:           "on_dependency with set_status",
			action:         nullOverdueAction(dbgen.OverdueActionSetStatus),
			statusName:     statusName("skipped"),
			recurrenceType: dbgen.RecurrenceTypeOnDependency,
			hasDue:         true,
			wantErr:        false,
		},
		{
			name:           "on_dependency with advance_recurrence rejected",
			action:         nullOverdueAction(dbgen.OverdueActionAdvanceRecurrence),
			recurrenceType: dbgen.RecurrenceTypeOnDependency,
			hasDue:         true,
			wantErr:        true,
			errContains:    "not valid for one-off or dependency-driven tasks",
		},

		// ─── Scheduled recurring tasks ─────────────────────────────────────────────
		{
			name:           "completion_based with advance_recurrence",
			action:         nullOverdueAction(dbgen.OverdueActionAdvanceRecurrence),
			recurrenceType: dbgen.RecurrenceTypeCompletionBased,
			hasDue:         true,
			wantErr:        false,
		},
		{
			name:           "fixed_non_accumulating with advance_recurrence",
			action:         nullOverdueAction(dbgen.OverdueActionAdvanceRecurrence),
			recurrenceType: dbgen.RecurrenceTypeFixedNonAccumulating,
			hasDue:         true,
			wantErr:        false,
		},
